#include<bits/stdc++.h>
using namespace std;
char s[200010];
int main()
{
	int n,ans=0;
	scanf("%d%s",&n,s);
	int now='-';
	for(int i=0;i<n;i+=2)
	{
		if(s[i]!=s[i+1])
		{
			if(s[i]!=now)
			{
				ans++;
				now=s[i];
			}
		}
	}
	if(now=='H')
	{
		ans--;
	}
	printf("%d",ans);
	return 0;
}
